--
-- Structure de la table `${schema}`
--

CREATE TABLE IF NOT EXISTS `${schema}` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `slug` varchar(255) NOT NULL,
  `url` varchar(255) DEFAULT NULL,
  `image` varchar(255) DEFAULT NULL,
  `background_image` varchar(255) DEFAULT NULL,
  `background_color` varchar(7) DEFAULT NULL,
  `owner_id` bigint(20) DEFAULT NULL,
  `is_published` tinyint(1) NOT NULL DEFAULT '0',
  `is_new` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` datetime NOT NULL,
  `updated_at` datetime NOT NULL,
  `uid` bigint(20) DEFAULT NULL,
  `store` longtext,
  `eve_id` varchar(100) DEFAULT NULL,
  `custom_fields` text,
  `age_min` smallint(6) DEFAULT NULL,
  `age_max` smallint(6) DEFAULT NULL,
  `accessibility` varchar(255) DEFAULT NULL,
  `type` varchar(2) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `slug` (`slug`),
  UNIQUE KEY `id_idx` (`id`),
  UNIQUE KEY `slug_idx` (`slug`),
  UNIQUE KEY `uid` (`uid`),
  UNIQUE KEY `uid_idx` (`uid`),
  UNIQUE KEY `eve_id` (`eve_id`),
  KEY `owner_id_idx` (`owner_id`)
) ENGINE=InnoDB AUTO_INCREMENT=174306 DEFAULT CHARSET=utf8;

